import{_ as t,o as e,c as r,ag as o}from"./chunks/framework.CLqXlKno.js";const u=JSON.parse('{"title":"功能介绍","description":"","frontmatter":{},"headers":[],"relativePath":"features.md","filePath":"features.md"}'),i={name:"features.md"};function d(l,a,n,h,s,c){return e(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="功能介绍" tabindex="-1">功能介绍 <a class="header-anchor" href="#功能介绍" aria-label="Permalink to &quot;功能介绍&quot;">​</a></h1><p>StoryForge 提供完整的 AI 视频创作解决方案，涵盖从素材导入到成片导出的全流程。</p><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><h3 id="剧情分析" tabindex="-1">剧情分析 <a class="header-anchor" href="#剧情分析" aria-label="Permalink to &quot;剧情分析&quot;">​</a></h3><p>AI 深度理解视频叙事结构，自动识别高光时刻与情感曲线，提取关键帧和场景信息。</p><h3 id="智能剪辑" tabindex="-1">智能剪辑 <a class="header-anchor" href="#智能剪辑" aria-label="Permalink to &quot;智能剪辑&quot;">​</a></h3><p>基于 AI 分析结果，一键生成专业级剪辑方案，支持多种剪辑策略和模板。</p><h3 id="ai-配音" tabindex="-1">AI 配音 <a class="header-anchor" href="#ai-配音" aria-label="Permalink to &quot;AI 配音&quot;">​</a></h3><p>多音色 AI 配音，支持中文、英文及多种方言，可调节语速、音调等参数。</p><h3 id="智能混剪" tabindex="-1">智能混剪 <a class="header-anchor" href="#智能混剪" aria-label="Permalink to &quot;智能混剪&quot;">​</a></h3><p>自动识别节奏卡点，多素材智能拼接与转场，生成节奏感强的混剪视频。</p><h3 id="字幕生成" tabindex="-1">字幕生成 <a class="header-anchor" href="#字幕生成" aria-label="Permalink to &quot;字幕生成&quot;">​</a></h3><p>支持 ASR 自动字幕提取和 OCR 字幕识别，多格式字幕文件导出。</p><h3 id="自动包装" tabindex="-1">自动包装 <a class="header-anchor" href="#自动包装" aria-label="Permalink to &quot;自动包装&quot;">​</a></h3><p>智能字幕样式、封面设计，片头片尾生成，让视频更加专业。</p><h2 id="导出格式" tabindex="-1">导出格式 <a class="header-anchor" href="#导出格式" aria-label="Permalink to &quot;导出格式&quot;">​</a></h2><p>StoryForge 支持多种导出格式，适配不同平台需求：</p><table tabindex="0"><thead><tr><th>格式</th><th>说明</th></tr></thead><tbody><tr><td>剪映草稿</td><td>兼容剪映项目文件</td></tr><tr><td>Premiere Pro</td><td>PR 项目文件 (.prproj)</td></tr><tr><td>Final Cut Pro</td><td>FCP 项目文件</td></tr><tr><td>DaVinci Resolve</td><td>DaVinci 项目文件</td></tr><tr><td>标准视频</td><td>MP4、MOV 等通用格式</td></tr></tbody></table><h2 id="工作流程" tabindex="-1">工作流程 <a class="header-anchor" href="#工作流程" aria-label="Permalink to &quot;工作流程&quot;">​</a></h2><p>完整的视频创作流程：</p><ol><li><strong>导入素材</strong> - 支持多种视频格式导入</li><li><strong>AI 分析</strong> - 智能分析视频内容</li><li><strong>生成文案</strong> - AI 生成解说词</li><li><strong>视频合成</strong> - 智能拼接与转场</li><li><strong>导出成片</strong> - 多格式导出</li></ol>',21)])])}const b=t(i,[["render",d]]);export{u as __pageData,b as default};
